class Solution:
    def minCost(self, grid):
        m = len(grid)
        n = len(grid[0])
        best = [None]
        def rec(i, j, acc):
            acc ^= grid[i][j]
            if i == m - 1 and j == n - 1:
                if best[0] is None or acc < best[0]:
                    best[0] = acc
                return
            if i + 1 < m:
                rec(i + 1, j, acc)
            if j + 1 < n:
                rec(i, j + 1, acc)
        rec(0, 0, 0)
        return best[0]

