class Solution:
    def minCost(self, grid):
        m = len(grid)
        n = len(grid[0])
        dp = [[None] * n for _ in range(m)]
        dp[0][0] = {grid[0][0]}
        for i in range(m):
            for j in range(n):
                if i == 0 and j == 0:
                    continue
                s = set()
                if i > 0 and dp[i - 1][j] is not None:
                    for v in dp[i - 1][j]:
                        s.add(v ^ grid[i][j])
                if j > 0 and dp[i][j - 1] is not None:
                    for v in dp[i][j - 1]:
                        s.add(v ^ grid[i][j])
                dp[i][j] = s
        return min(dp[m - 1][n - 1])

