var minCost = function(grid) {
    const m = grid.length;
    const n = grid[0].length;
    const dp = Array.from({length: m}, () => new Array(n).fill(null));
    dp[0][0] = new Set([grid[0][0]]);
    for (let i = 0; i < m; i++) {
        for (let j = 0; j < n; j++) {
            if (i === 0 && j === 0) continue;
            const s = new Set();
            if (i > 0 && dp[i - 1][j] !== null) {
                for (const v of dp[i - 1][j]) s.add(v ^ grid[i][j]);
            }
            if (j > 0 && dp[i][j - 1] !== null) {
                for (const v of dp[i][j - 1]) s.add(v ^ grid[i][j]);
            }
            dp[i][j] = s;
        }
    }
    return Math.min(...dp[m - 1][n - 1]);
};
